import { getPitchRange } from "../appData.js";

export const level2 = {
  num: 2, name: "Pitch & Range", focus: "Passaggio, register transitions, pitch accuracy, auditory-motor integration",
  duration: "45 min",
  setup: "Standing. Live Pitch Detector on. Guitar needed for v2e5, v2e6, and v2e7. Straw nearby. Water.",
  subtitle: "Tuning the Instrument",
  description: "Your voice has a break point around A3 where chest voice transitions to head voice — your passaggio. Every singer has one, and every great singer has learned to navigate it. These exercises map that transition zone, train smooth crossings, and build pitch accuracy across your range. But more importantly, they train your brain's auditory-motor loop — the neural circuit that predicts what pitch you are about to sing, compares it to what actually comes out, and makes corrections in real-time. This is where your voice goes from an instrument you own to an instrument you can actually play.",
  artists: "Jeff Buckley, Thom Yorke, Angus Stone (DOPE LEMON), Mark Speer (Khruangbin), Matthew Young (Allah-Las)",
  unlocks: "Building the Inner Ear (Level 3)",
  exercises: [
    {
      id: "v2e0", time: 5, title: "Where Is Your Pitch? — Diagnostic Pre-Test", type: "record",
      what: "Before training pitch accuracy, assess where you actually are. This diagnostic records your current pitch-matching ability, identifies your passaggio location precisely, and gives you concrete data to measure progress against. No judgment — just honest measurement.",
      setup: "Standing. Pitch Detector on. Guitar or piano app for reference notes. Recorder on.",
      recorder: true,
      referencePitches: getPitchRange("E3", "C4"),
      steps: [
        { text: "Play C3 on your guitar or piano app. Listen for 2 seconds. Then sing it on 'ah.' Hold for 3 seconds. Watch the pitch detector — how close are you? Write down: exact match, slightly sharp, slightly flat, or way off.", why: "Pitch matching is the foundation of singing in tune, and it involves a neural circuit called the auditory-motor loop. When you hear a pitch, your auditory cortex processes the frequency. Your motor cortex then sends commands to the laryngeal muscles to produce that frequency. But here is the crucial part: your brain does not just react to the pitch — it PREDICTS what pitch your voice will produce based on past experience. This prediction is called a 'forward model.' If the prediction is wrong, you sing flat or sharp. This diagnostic tells you how accurate your forward model currently is. Think of it like a GPS that has not been calibrated yet — it knows roughly where you are, but the precision needs work." },
        { text: "Repeat for E3, G3, A3, Bb3, C4. Six notes spanning your chest voice, passaggio, and lower head voice. For each note: play it, listen, sing it, rate your accuracy. Write down all six ratings.", why: "Testing across a range reveals WHERE your pitch accuracy breaks down. Most singers are reasonably accurate in their comfortable chest voice (C3-G3) and significantly less accurate near and above the passaggio (A3-C4). The passaggio introduces a mechanical complication: the vocal fold configuration is changing, which alters the relationship between muscle effort and pitch. Your brain's forward model was built on chest voice experience, and it may not yet have accurate predictions for the passaggio zone. Identifying exactly where accuracy degrades tells you where to focus your training." },
        { text: "Sing a C major scale: C3-D3-E3-F3-G3-A3-B3-C4, ascending, one note per beat at 60 BPM. Record the whole thing and listen back. Where does the pitch start to waver or go flat?", why: "The ascending scale is a stress test for your pitch accuracy because each higher note requires a slightly different laryngeal configuration. Going flat on the upper notes is the most common pattern and usually indicates insufficient cricothyroid engagement — the muscle that stretches the vocal folds for higher pitches is not activating strongly enough. Going sharp usually indicates too much subglottic pressure — pushing too much air for the pitch. The scale also reveals your passaggio location: the note where your tone quality changes most dramatically is your primary passaggio. For most male singers with your voice type, this is between Ab3 and Bb3." },
        { text: "Now descend: C4-B3-A3-G3-F3-E3-D3-C3 at 60 BPM. Descending is usually easier than ascending because the vocal folds naturally relax as pitch drops. If your ascending scale was shaky but your descending scale is clean, that confirms the issue is in the upward register transition, not overall pitch accuracy.", why: "Comparing ascending and descending accuracy isolates the variable. If both are equally inaccurate, your pitch-matching mechanism itself needs training (exercises v2e1 through v2e3). If only ascending is inaccurate, the issue is specifically the register transition — your brain's forward model does not yet know how to predict pitch accurately during the chest-to-head transition. This is fixable and common. Descending accuracy is usually better because the vocal folds are relaxing into a more familiar (chest) configuration, and your brain has more experience with chest voice pitch relationships." },
        { text: "Passaggio probe: sing a slow glide from G3 to C4 on 'ooh.' This should take about 5 seconds. Listen and feel for the exact pitch where your voice changes quality — where the tone shifts from warm and full to lighter and thinner. This is YOUR passaggio. It may be A3, Ab3, Bb3, or even B3. Record what you find.", why: "Every voice has a slightly different passaggio location, and it can even shift day to day depending on warm-up status, hydration, and fatigue. For your tenor voice, the primary passaggio typically sits between Ab3 and Bb3, with A3 being the statistical center. But your voice is unique, and the exact location matters for the exercises that follow. Knowing your passaggio to within a half step lets you target exercises precisely at the transition zone rather than guessing. This is personalized training — the vocal equivalent of knowing your exact shoe size instead of buying 'medium.'" },
        { text: "Close your eyes. Have the guitar play a random note in the range E3-C4 (or use a random pitch generator). Without seeing the note name, sing it back. Try 5 random notes. How many can you match within a half step?", why: "Eyes-closed pitch matching removes the visual crutch of seeing the note name or watching the pitch detector. When your eyes are closed, your brain must rely entirely on its auditory processing and motor prediction — the raw auditory-motor loop without external assistance. Most untrained singers can match 2-3 out of 5 random notes within a half step. By the end of Level 2, you should match 4-5 out of 5. This improvement represents genuine neural pathway development — your auditory cortex is learning to extract pitch information more precisely, and your motor cortex is learning to translate that information into accurate vocal fold adjustments." },
        { text: "Record a final note: sing A3 (your approximate passaggio) and hold it for 5 seconds. Listen back. Is it steady or does it waver? Is the pitch accurate or has it drifted? How does the tone quality sound? This is your passaggio baseline — the specific measurement that Level 2 is designed to improve.", why: "A3 sustained for 5 seconds is the single most revealing test of your current vocal development. It sits at the register transition, so it tests your ability to maintain a stable fold configuration at the most mechanically challenging point in your range. Wavering indicates instability in the laryngeal muscles. Drift indicates that your breath support is not steady enough to maintain consistent subglottic pressure. Rough tone quality indicates that the vocal folds are not adducting cleanly at this pitch. All of these issues are addressed by the exercises in this level. Save this recording — it is your before picture." }
      ],
      feel: "This should feel like an honest assessment, not a test you need to pass. Some notes will be easy, some will be hard. The passaggio probe will likely feel unstable — that is normal and expected. The eyes-closed exercise might feel disorienting at first. All of this is data that helps you train more effectively.",
      wrong: "Do not try to 'ace' the diagnostic by warming up extensively first or choosing easier notes. The diagnostic works best when it captures your current unvarnished state. If you warm up first, you are measuring your warmed-up ability, not your baseline. Also: do not use vibrato to mask pitch inaccuracy. Sing straight tones for the diagnostic so the pitch detector can give you clean readings.",
      sarah: "Every student I work with does this diagnostic, and every one of them is surprised by something. Usually it is that their pitch is better than they thought in some areas and worse in others. The diagnostic turns vague worry ('I am not a good singer') into specific, actionable data ('I go flat on ascending notes above A3'). Specific problems have specific solutions. Vague worry has no solution. That is why we measure.",
      levelUp: "Completed all recordings and notes. You have a clear picture of your pitch accuracy across your range, your passaggio location, and your eyes-closed matching ability."
    },
    {
      id: "v2e1", time: 5, title: "Descending 5-Note Scale — Through the Break", type: "vocal",
      pitchContour: true,
      what: "Start above your break on a comfortable note, descend through A3 on a single vowel. The voice naturally transitions from head/mix into chest. You are observing where that happens, not forcing it. Descending through the break is easier than ascending because the vocal folds naturally thicken as pitch drops, which is the direction the break wants to go. This exercise trains the forward model by giving your brain repeated, predictable experiences of the register transition.",
      setup: "Standing. Pitch Detector on. Conversational volume, 6/10. No guitar.",
      referencePitches: getPitchRange("E3", "C4"),
      metronome: 80,
      recorder: true,
      steps: [
        { text: "Start on C4. Sing: C4-B3-A3-G3-F3 on 'nee.' One note per beat at 80 BPM. Smooth and connected — no gaps between notes. Conversational volume, like you are talking to someone across a table.", why: "Starting above the break and descending through it lets the voice transition naturally from head/mix into chest voice. 'Nee' is chosen deliberately: the 'n' consonant routes sound through the nasal cavity (forward placement), and the 'ee' vowel narrows the vocal tract, both of which help the voice negotiate the register transition more smoothly. The conversational volume is critical — loud singing engages too much chest voice pull, masking the transition. Quiet singing exposes it, which is exactly what you need for training. You want to FEEL the break, not power through it. At 6/10 volume, the passaggio reveals itself honestly." },
        { text: "Listen for the 'settling' moment. Around Bb3 or A3, the tone will get slightly warmer, heavier, more chest-resonant. It is like stepping off a low curb — a subtle shift in weight. That moment is your passaggio. Mark the exact note where you feel it.", why: "The 'settling' sensation is the thyroarytenoid muscles (inside the vocal folds) engaging more fully, adding mass to the vibrating edge of the folds. In head voice, the folds are thin and stretched. As you descend through the passaggio, the TA muscles add bulk, and the tone transitions from bright and light to warm and full. This is not something to fight — it is a natural and desirable transition. The goal is not to eliminate the register shift but to make it gradual rather than abrupt. By marking the exact note, you build a precise mental map of your passaggio that helps you anticipate and navigate it in real singing." },
        { text: "Each round starts a half step lower: Round 2 starts on B3, Round 3 on Bb3, Round 4 on A3. As the starting note descends, the critical transition zone moves to a different spot in each round.", why: "Lowering the starting pitch each round ensures you are not just training one specific transition path. Your brain needs multiple experiences of crossing the passaggio from different starting points to build a generalized motor program for the transition. If you only practice one path, you develop a specific skill that may not transfer to actual singing, where the passaggio can be approached from any direction. This variability of practice is a core principle of motor learning — varied practice produces more robust, transferable skills than repetitive practice of a single pattern." },
        { text: "Volume check: maintain 6/10 throughout. If you find yourself getting louder as you descend (the natural tendency — chest voice invites more volume), consciously hold back. The quieter you are, the more the transition reveals itself.", why: "There is a powerful reflex to increase volume as you enter chest voice because the thicker vocal fold configuration can handle more subglottic pressure. But louder singing masks the transition by overpowering the subtle tonal changes that signal the register shift. At 6/10 volume, you can hear every nuance of the transition — the exact moment the tone warms, the exact point where the flip happens. This information is what your brain needs to build its forward model. Think of it like learning to drive: you learn in a parking lot at low speed before you merge onto the highway. Low volume is your parking lot." },
        { text: "On Round 4 (starting on A3), you are beginning IN the break zone and descending through it. This is the hardest round because there is no head voice runway. The voice must negotiate the transition from the very first note.", why: "Starting in the passaggio tests whether you can access the transition zone without the momentum of descending from above. In real singing, you often have to sing notes in the passaggio without a convenient approach from above or below — a melody might jump directly to A3 or Bb3. This round trains that 'cold entry' into the passaggio, building the muscle memory for accessing the break zone from any context. If this round feels dramatically harder than Rounds 1-2, that is normal and indicates that your brain's forward model for the passaggio is still developing." },
        { text: "Now change the vowel: repeat all 4 rounds on 'mah' instead of 'nee.' The open 'ah' vowel exposes the break more than the closed 'ee.' You should notice the transition more clearly — possibly even a small crack or flip.", why: "Vowel choice dramatically affects the ease of the passaggio crossing. 'Nee' (closed vowel, nasal consonant) is the easiest — it provides natural forward placement and a partially occluded vocal tract. 'Mah' (nasal consonant but open vowel) removes the vowel protection, exposing the break more honestly. If you can descend smoothly on 'nee' but crack on 'mah,' it means the closed vowel was doing some of the work for you. The goal is eventually to cross smoothly on ANY vowel, but you build up to that by starting easy (nee) and progressively removing supports (mah, then 'ah' with no nasal consonant). This graduated challenge is how all skill learning works." },
        { text: "Final round: descend C4-B3-A3-G3-F3 on 'ah' — no nasal consonant, no closed vowel. Pure open tone through the break. This is the hardest version. Even a small improvement here represents significant vocal development.", why: "The open 'ah' is the most exposed vowel for the passaggio because it provides no acoustic protection — no nasal resonance, no lip rounding, no tongue narrowing. The vocal folds are on their own. If you can descend smoothly through the break on 'ah' at 6/10 volume, your register transition is genuinely coordinated. Most singers at this stage will hear a wobble or subtle quality shift on 'ah' that was not present on 'nee.' That gap between your easiest and hardest vowel is your current 'vowel freedom' in the passaggio. Level 2 aims to close that gap." },
        { text: "Record your final 'ah' descent and compare it to your first 'nee' descent. The 'nee' should sound smooth. The 'ah' should sound less smooth. That difference is your training target for the weeks ahead.", why: "The comparison gives you a concrete, audible measure of where the passaggio training needs to go. As you practice daily, the 'ah' descent will gradually approach the smoothness of the 'nee' descent. When they sound identical — when the break is equally smooth on any vowel — you have achieved vowel-independent passaggio crossing, which is one of the key Level 2 graduation criteria. Recording both on the same day and labeling them with the date creates a longitudinal record of your progress. Revisiting these recordings weekly provides the motivational fuel to keep practicing." }
      ],
      feel: "Around Bb3-A3, you will notice the voice 'settling' — like stepping off a curb. The tone gets slightly heavier, warmer, more chest-resonant. The 'nee' vowel naturally brightens the sound, making the transition smoother. On 'ah,' the transition may feel more abrupt. Both experiences are valuable data.",
      wrong: "If you are straining to keep the same tone quality all the way down, you are fighting the flip. Let it happen. The voice WANTS to shift — your job is to make the shift gradual, not prevent it. If you are gripping your throat to maintain head voice below the break, release immediately. The descent into chest voice should feel like a release, not a fight.",
      sarah: "Why 'nee'? The closed vowel plus nasal consonant keeps the sound forward and bright, which encourages mix voice through the break. But the real lesson here is not any single vowel — it is the FEELING of a smooth transition. Once you know what smooth feels like on 'nee,' you can chase that same feeling on harder vowels. Your body learns from success, so start with the easy vowel, nail it, then transfer the feeling.",
      levelUp: "Smooth descent through the break zone with no audible crack on 3 consecutive rounds. The transition is gradual on 'nee' and improving on 'ah.'"
    },
    {
      id: "v2e1b", time: 6, title: "Passaggio Slides — Glissando Training", type: "vocal",
      drone: { root: "A", octave: 3, texture: "pure" },
      pitchContour: true,
      what: "Gentle pitch slides (glissando) across the break zone (F3-B3). The 'ooh' vowel keeps the larynx relaxed, letting you slide up and down slowly through the break instead of jumping across it. While the descending scale (v2e1) lets you observe the break, slides let you TRAIN it — spending extended time in the transition zone, forcing the muscles to negotiate the shift in slow motion.",
      setup: "Standing. Pitch Detector on. Relaxed jaw, no guitar. Conversational volume.",
      referencePitches: getPitchRange("E3", "C4"),
      metronome: 70,
      recorder: true,
      steps: [
        { text: "Start on F3 with a relaxed 'ooh.' Slide slowly up to B3 over 3-4 seconds. Do not jump — glide continuously, visiting every micro-pitch between F3 and B3. Think of it as a ramp, not a staircase.", why: "A slow glide forces the vocal folds to make the register transition gradually instead of flipping. When you sing discrete notes (scales), your brain can 'cheat' by adjusting the fold configuration in the gaps between notes. A continuous glide eliminates the gaps, forcing the transition to happen in real-time. The 'ooh' vowel naturally lowers the larynx (because the rounded lips lengthen the vocal tract), which reduces tension in the extrinsic laryngeal muscles and gives the intrinsic muscles more freedom to negotiate the transition. This is why 'ooh' is the first vowel you learn to slide on — it creates the most favorable mechanical conditions for a smooth passaggio crossing." },
        { text: "Slide back down from B3 to F3 on the same 'ooh.' Listen for the spot where the tone changes quality. Going down, the transition often feels smoother than going up. If it does, that tells you the upward transition needs more work.", why: "The downward slide reveals the break from the other direction. Most singers find the transition smoother going down because the vocal folds are relaxing from stretched (head/mix) to thick (chest), which is the direction of passive elastic recoil. Going up requires active muscular engagement (the cricothyroid stretching the folds), which is harder to control. The asymmetry between your ascending and descending smoothness quantifies how much work the ascending transition needs. If both directions feel equally smooth, you are further along than most Level 2 students." },
        { text: "Repeat 4 times, making each slide smoother. The goal: no audible 'bump' or crack in the middle. Each pass, focus on the exact moment where the voice wants to flip and try to slow down through that zone.", why: "Repetition is essential for motor learning, but mindless repetition is nearly worthless. Each pass needs a focus — in this case, the exact moment of transition. By slowing down through the crack zone on each repetition, you are giving your brain more time to process the sensory feedback from that specific moment. Research on motor learning shows that focused practice on the hardest part of a skill (called 'deliberate practice') produces faster improvement than evenly-paced practice through the entire movement. The crack zone is the hardest part, so spending disproportionate time there is the most efficient use of your practice." },
        { text: "Now try the slide on 'ee' — a harder vowel for the break. 'Ee' narrows the vocal tract and raises the tongue, which can expose the break more aggressively. Slide F3 to B3 on 'ee' and notice how the transition feels different — likely rougher, with a more pronounced bump.", why: "'Ee' is harder because the high tongue position and narrow vocal tract create acoustic conditions that amplify the register discontinuity. In acoustic terms, 'ee' has a high first formant that conflicts with the fundamental frequency shift during the passaggio, creating a moment where the vocal tract is poorly matched to the vocal fold vibration pattern. On 'ooh,' the formants are positioned to ease the transition. On 'ee,' they fight it. If you can slide smoothly on 'ee,' you have achieved a mechanically robust passaggio crossing that will survive any vowel in any song. But start with 'ooh' and graduate to 'ee' — do not torture yourself on the hard vowel before you have nailed the easy one." },
        { text: "Combine the two vowels: slide F3 to B3 on 'ooh,' hold B3 for 2 seconds, then slide B3 back down to F3 on 'ee.' This tests both vowels and both directions in one continuous exercise.", why: "The combination exercise introduces variable practice — alternating between conditions that require slightly different motor strategies. Your brain must switch from 'ooh' configuration to 'ee' configuration at the top of the slide while maintaining smooth phonation. This switching ability is essential for real singing, where vowels change constantly within a phrase. If the switch from 'ooh' to 'ee' on B3 causes a crack or quality change, that is the transition between vowel shapes fighting the register transition. Both become smooth with practice." },
        { text: "Extend the range: slide from E3 to C4 on 'ooh.' This wider slide takes you deeper into both chest voice (E3) and head voice (C4), increasing the distance the voice must travel through the passaggio. Take 5-6 seconds for the full ascent.", why: "The extended range slide challenges your entire register transition mechanism. E3 is firmly in chest voice. C4 is above the break in head/mix. The journey between them requires a complete reconfiguration of the vocal fold vibration pattern, and doing it as a continuous glide means every intermediate configuration is visited. This is like a full-range stretching exercise for the passaggio muscles. The slower pace (5-6 seconds) ensures you do not rush through the transition zone. Many singers instinctively speed up through the uncomfortable part, which defeats the purpose. Slow and steady through the break is the mantra." },
        { text: "Micro-slides: stay in the passaggio zone ONLY. Slide from Ab3 to Bb3 and back, repeatedly, for 30 seconds. This tiny range (just two half steps) keeps you in the transition zone the entire time. It will feel unstable and uncomfortable. That is the point.", why: "Micro-slides are the most targeted passaggio training exercise because they confine your voice to the exact zone where the register transition occurs. There is nowhere to hide in comfortable chest or head voice — you are living in the break for 30 straight seconds. This concentrated exposure forces the vocal fold muscles to find a stable configuration for the transition zone rather than defaulting to one register or the other. The instability you feel is the muscles searching for coordination. With daily practice over 2-3 weeks, the instability decreases measurably. This is the associative stage of motor learning — your muscles are learning the pattern but have not yet automated it." },
        { text: "End with a full-range sigh: start at the top of your comfortable range and slide all the way down to your lowest note on 'haah.' No effort, just a release. This resets your voice after the intensity of the passaggio work.", why: "The reset sigh serves two purposes: it releases any tension that accumulated during the passaggio slides, and it provides a contrast experience. After the focused, controlled slides, the unrestricted sigh should feel completely free. If the sigh still feels tight or restricted, residual tension is present and needs to be released before moving on. The sigh also demonstrates what your voice sounds like when it is not working hard — this effortless quality is the ultimate goal. All technique training aims to make singing feel as easy as this sigh." }
      ],
      feel: "The slide should feel like a gentle elevator ride, not a staircase. The tone changes character through the break zone, but there should not be a gap or crack — just a gradual shift from warm to bright. The micro-slides will feel wobbly and unstable at first — that is the muscles learning, not failing.",
      wrong: "If the voice cuts out or cracks sharply in the middle, you are sliding too fast or using too much air. Slow down and reduce volume. The slide should be quiet and gentle — 5/10 volume at most. If the 'ee' slide cracks badly, go back to 'ooh' and do 3 more passes before trying 'ee' again. Do not push through cracks aggressively — that trains bad habits into the muscle memory.",
      sarah: "Glissando through the passaggio is like stretching a tight muscle — you go slow, you stay relaxed, and you let the body figure out the coordination. Forcing it just makes it tighter. The micro-slides are where the real magic happens. Thirty seconds of living in the break zone does more for your transition than ten minutes of scales that pass through it briefly. Stay in the discomfort. That is where growth lives.",
      levelUp: "Smooth 'ooh' glide from F3 to B3 and back with no audible crack, 3 times in a row. Micro-slides through Ab3-Bb3 feel more stable than they did at the start of the exercise."
    },
    {
      id: "v2e2", time: 5, title: "Messa di Voce — The Dynamic Test", type: "vocal",
      drone: { root: "A", octave: 3, texture: "pure" },
      volumeMeter: true,
      what: "Sing a single note in your break zone. Start as quiet as possible, swell to medium volume, back to quiet. The crescendo challenges the vocal fold configuration because louder singing engages more chest voice pull. The goal: stay in mix through the entire swell, maintaining tone quality regardless of volume. This is the gold standard exercise for building a seamless register blend.",
      setup: "Standing. Breathe into your ribs (appoggio from Level 1). Pitch Detector on. Volume Meter on.",
      referencePitches: getPitchRange("G3", "C4"),
      metronome: 60,
      recorder: true,
      steps: [
        { text: "Sing 'ah' on G3 at piano (pp) — as quiet as possible while still producing a pitched tone, not just air. Hold for 2 seconds. Feel which register you are in.", why: "G3 is below the break for most tenors — it should feel comfortable in chest voice. Starting at pp (very quiet) is important because quiet singing requires precise vocal fold adduction. At pp, the folds are barely touching, producing a gentle tone. This is your baseline — easy pitch, easy volume. The messa di voce works by gradually making things harder from this easy starting point, so the body learns to adapt incrementally rather than hitting a wall. Think of it like heating a frog slowly versus dropping it in boiling water — the gradual approach allows the muscles to adjust." },
        { text: "Swell to mezzo forte (mf) over 3 seconds. Then decrescendo back to pp over 3 seconds. Total duration: approximately 8 seconds on one breath. The volume change should be smooth and continuous — a gradient, not steps.", why: "The swell challenges your breath support because increasing volume requires increasing subglottic pressure. Your ribs (appoggio from Level 1) must maintain expansion while the diaphragm increases its upward push. The decrescendo is actually harder because you must reduce subglottic pressure smoothly while maintaining vocal fold closure. Most untrained singers can swell reasonably well but crash on the decrescendo — the voice either dies abruptly or cracks as the volume drops below the threshold needed to maintain the current register configuration. The messa di voce literally means 'placing the voice' in Italian, and it has been the cornerstone exercise of vocal training since the 17th century." },
        { text: "Do 3 cycles on G3. Focus on the decrescendo — making the fade back to pp as smooth as the swell to mf. Listen to the pitch detector: does the pitch drift as the volume changes? It should stay rock-steady on G3 throughout.", why: "Pitch drift during volume change indicates inadequate breath support. When subglottic pressure increases (crescendo), many singers go sharp because the increased air pressure pushes the vocal fold vibration rate higher. When pressure decreases (decrescendo), they go flat because there is insufficient pressure to maintain the target frequency. Maintaining steady pitch through dynamic changes requires the auditory-motor loop to actively compensate — your brain must adjust the laryngeal muscle tension to counteract the effect of changing air pressure. This is a sophisticated neural coordination that improves with practice. Three cycles on a comfortable note (G3) build the pattern before you move to harder pitches." },
        { text: "Move to Ab3. Same exercise: pp swell to mf, back to pp. 3 cycles. Notice: is it harder? The break zone is getting closer, and the crescendo is starting to pull the voice toward a register decision.", why: "Ab3 is one half step closer to your passaggio than G3. That single half step increases the challenge noticeably because the vocal folds are in a more ambiguous configuration — not firmly in chest voice, not firmly in mix. The crescendo on Ab3 may feel like the voice is being 'pulled' toward chest voice, especially at the mf peak. This pull is the thyroarytenoid muscles engaging more strongly with increased subglottic pressure. Resisting this pull — staying in mix rather than dropping into full chest — is the exact skill the messa di voce trains. Each half step higher makes the pull stronger and the exercise more educational." },
        { text: "Move to A3 — your passaggio center. This is the real test. Swell from pp to mf on A3 and listen for the moment where the voice wants to flip or crack during the crescendo. If it flips, reduce your maximum volume — stop at mp instead of mf.", why: "A3 is the critical pitch where your voice most wants to make a register decision. At pp, the thin fold configuration (mix/head) is stable. As volume increases toward mf, the growing subglottic pressure wants to engage the thyroarytenoid muscles and flip the voice into full chest. This flip is the crack you hear in untrained voices. The messa di voce teaches your muscles to resist this flip by maintaining the thin-fold configuration against increasing pressure. If it flips at mf, reducing to mp keeps you in the productive training zone — challenging but achievable. Over weeks of practice, your maximum volume on A3 without flipping will increase. This is measurable progress." },
        { text: "Move to Bb3. Swell from pp to mp (not mf — Bb3 is above the break for most tenors, so the dynamic range will be smaller). 3 cycles. The decrescendo on Bb3 may feel like the voice wants to 'fall off' into head voice. Let it settle into a gentle head/mix — do not chase chest voice up here.", why: "Above the primary passaggio, the messa di voce tests the opposite challenge: instead of the crescendo pulling toward chest, the decrescendo may allow the voice to thin out excessively and lose projection. The skill at Bb3 is maintaining enough fold contact during the pp to produce a supported, present tone rather than a wispy, unsupported one. This is the 'supported piano' — quiet singing with full breath support — and it is one of the hardest dynamic skills in singing. Many professional singers consider the supported piano more difficult than belting because it requires exquisite control with minimal margin for error." },
        { text: "Vowel modification integration: repeat the A3 messa di voce, but this time let the vowel shift. Start the pp on 'ah.' As you swell toward mf, let 'ah' drift toward 'uh.' On the decrescendo back to pp, let 'uh' drift back toward 'ah.' The vowel modification should happen naturally, not as a deliberate switch.", why: "Vowel modification during the swell lowers the first formant, which helps the vocal folds thin out for mix voice instead of hitting the chest voice ceiling. This is the same principle from Level 1's formant shaping work (v2e3b) applied in real-time during a dynamic exercise. The 'ah' to 'uh' drift is subtle — not a dramatic vowel change but a gradual rounding of the vowel that gives the voice more room to navigate the crescendo without cracking. This automatic vowel modification is what trained singers do unconsciously on every passaggio note. You are training the automation that will eventually happen without thought." },
        { text: "Final challenge: messa di voce on A3 with the smoothest possible swell and fade, vowel modification, and steady pitch. Record it and listen back. Rate yourself 1-10 on smoothness, pitch stability, and tone quality. This is your messa di voce benchmark for future comparison.", why: "Self-rating on specific criteria develops your critical listening skills — your ability to hear what your voice is actually doing rather than what you THINK it is doing. Most beginning singers rate themselves higher than an expert would, which is not a problem — it just reflects the developing ear. As your ear improves through training, your self-ratings will become more accurate and more demanding. The recorded benchmark serves the same purpose as the Level 1 baseline recording: a concrete artifact that makes progress audible over time. The messa di voce on A3 is arguably the single most revealing measure of vocal development for a tenor singer." }
      ],
      feel: "On G3, this should feel effortless. On Ab3, you will feel a 'choice point' during the crescendo — a moment where the voice could go either way. On A3, the crescendo is the test — can you swell without the voice flipping? If it flips, that is fine — it is data. On Bb3, the decrescendo is the test — can you get quiet without losing support?",
      wrong: "If the swell sounds like a sudden jump from quiet to loud, slow down the crescendo. The gradient should take a full 3 seconds. If the voice cracks on A3, reduce your max volume — stop at mp instead of mf. Never push through a crack at volume — it trains the muscles to crack. Instead, find the volume ceiling just below the crack and practice there. The ceiling will rise over time.",
      sarah: "The messa di voce is the number one exercise for building a seamless mix. Quiet-loud-quiet on one note teaches your voice to navigate the break without flipping. It has been used for literally 400 years because nothing else trains the same coordination as efficiently. If you could only do one exercise from this entire level, this would be my choice. It is not flashy, but it is the exercise that makes the biggest difference.",
      levelUp: "Smooth swell on A3 without cracking at mp volume, 3 times in a row. Pitch stays within a quarter-tone throughout the dynamic change."
    },
    {
      id: "v2e3", time: 4, title: "Siren Glides — Full Range Diagnostic", type: "vocal",
      pitchContour: true,
      what: "Lip trill (or sustained 'vvv') gliding from your lowest note up to your highest and back. The lip trill adds SOVT backpressure which makes the transition through the break easier. This is both a warm-up and a diagnostic — it reveals the current state of your passaggio on any given day. Use it as your daily 'instrument check' before focused practice.",
      setup: "Standing. Lips loose. No guitar. Water nearby.",
      referencePitches: getPitchRange("C2", "G4"),
      steps: [
        { text: "Start a lip trill on your lowest comfortable note (approximately C2-E2 depending on the day). Glide UP to your highest comfortable head voice (approximately E4-G4). Take 4-5 seconds for the full ascent. One continuous sound, no breaks.", why: "The full-range siren maps your entire instrument in one pass. Under SOVT protection, you can safely explore the extremes of your range without risk of strain. The lip trill reduces vocal fold collision force by approximately 30% compared to open singing, making it safe to explore pitches you would not attempt on open vowels. The ascent reveals the current state of your passaggio: if the trill wobbles or thins dramatically around A3-Bb3, your transition zone is stiff today and needs extra warm-up. If it sails through smoothly, you are in good shape and can move to more demanding exercises." },
        { text: "Glide back DOWN in 4-5 seconds. Listen for where the trill wobbles or cuts out. These spots are your transition zones — the areas of maximum interest for training. Mark them mentally.", why: "The descent reveals different information than the ascent. Going up, the cricothyroid muscle is actively stretching the folds. Going down, the folds are relaxing back toward their resting configuration. Some singers find the downward transition smoother (the folds naturally want to relax) while others find it rougher (the voice 'falls' too fast through the break). Your specific pattern tells you which direction needs more work. The wobbling spots are not failures — they are the exact locations where your training will produce the most improvement. They are targets, not problems." },
        { text: "Rounds 3-5: SLOW DOWN through the Ab3-A3-Bb3 zone. Take 3-4 seconds just for those three notes — roughly one note per second — while the rest of the range moves at normal speed. Zoom in on the break.", why: "This is your passaggio zone. Slowing down here gives the vocal fold muscles more time to negotiate the register transition, which teaches them the coordination pattern more thoroughly. Fast transitions through the break allow the voice to 'skip over' the unstable zone, which feels easier but teaches nothing. Slow transitions force the muscles to find stable configurations at every micro-pitch within the break zone. It is the difference between running across hot coals (fast, no learning) and walking slowly on warm sand (slower, building tolerance). The discomfort is productive." },
        { text: "Rounds 6-7: vary the SOVT exercise. If lip trills feel easy, try 'vvv' (voiced V sound) through the same path. Or hum through a straw. Each SOVT variation provides a slightly different amount of backpressure and challenges the vocal folds differently.", why: "Different SOVT exercises work better on different days depending on your vocal fold condition, hydration, and fatigue. Having multiple options in your toolkit ensures you always have an effective warm-up available. Lip trills provide moderate backpressure. 'Vvv' provides less backpressure (it is closer to open singing). Straw phonation provides more backpressure (the narrower the straw, the more protection). On rough days, use the straw. On good days, use 'vvv' to challenge yourself. On average days, lip trills are the sweet spot. This adaptive approach to warm-up is how professional singers maintain their voices across varying conditions." },
        { text: "After the SOVT sirens, try an open siren: glide from your lowest to highest on 'ooh.' No lip trill, no straw — just the vowel. Compare the ease to the SOVT version. The passaggio should feel harder on 'ooh' but still manageable after the SOVT warm-up.", why: "The open siren tests whether the SOVT warm-up has transferred to open singing. If the 'ooh' siren feels almost as easy as the lip trill siren, the transfer is strong — your vocal folds have internalized the efficient phonation pattern from the SOVT work and are applying it to open singing. If the 'ooh' siren feels dramatically harder (big crack, voice cuts out), the transfer needs more work — you may need more SOVT passes before the folds are ready for open singing. This transfer from protected to unprotected singing is the entire purpose of SOVT warm-ups. The lip trill is not the goal — singing without it is." },
        { text: "Challenge siren: glide from lowest to highest on 'ah' — the most exposed vowel. This will reveal every weakness in your passaggio crossing without any acoustic protection. Note where it cracks or wobbles. These are your targeted training zones for the exercises that follow.", why: "The 'ah' siren is the most honest diagnostic in your vocal toolkit. It provides zero acoustic protection — no lip occlusion, no rounded vowel, no nasal consonant. Whatever your passaggio crossing genuinely sounds like, the 'ah' siren reveals it. Cracks and wobbles here are not failures but precision diagnostics: they tell you exactly where your vocal fold coordination needs work. Write down the specific notes where problems occur. Over weeks of training, these problem notes will shift — the crack might move from A3 to Bb3 as your low passaggio improves, and eventually it resolves entirely as the full transition becomes smooth." }
      ],
      feel: "The siren should feel like an elevator ride through your range. Chest voice feels warm and full at the bottom. Through the break, the trill may become uneven — that is normal. Head voice feels lighter, buzzier at the top. The uneven zone is your passaggio — exactly where you are training.",
      wrong: "If the trill STOPS during the break (complete cutout, not just unevenness), you are pushing too much air. Back off to 50% airflow. The trill should be continuous, even if it wobbles. Wobble is data. Cutout is too much pressure. If you cannot get through the break on lip trill, switch to straw phonation — the extra backpressure will bridge the gap.",
      sarah: "SOVT exercises like lip trills create backpressure that helps the vocal folds transition between registers more smoothly. Think of it as training wheels for the passaggio. But here is the thing — you do not want training wheels forever. Every siren session should include at least one open vowel siren so you are always testing whether the training wheels can come off yet. The day your 'ah' siren sails through the break smoothly is a milestone worth celebrating.",
      levelUp: "Complete full-range siren with continuous trill (wobbles OK, no complete cutouts) 3 times. Open 'ooh' siren with passaggio that is audibly smoother than when you started Level 2."
    },
    {
      id: "v2e3b", time: 6, title: "Vowel Formant Shaping — The Five Vowels Through the Break", type: "vocal",
      pitchContour: true,
      what: "Practice sustaining each vowel (ee-eh-ah-oh-oo) on a single pitch at the passaggio (A3), then move through the passaggio on each vowel. Some vowels cross easier than others — 'oo' and 'oh' are easiest, 'ee' and 'eh' are hardest. This exercise teaches you which vowels help the passaggio and which fight it, so you can make intelligent vowel choices when singing songs.",
      setup: "Standing. Pitch Detector on. No guitar. Relaxed jaw. Soft knees.",
      referencePitches: getPitchRange("G3", "C4"),
      metronome: 60,
      recorder: true,
      steps: [
        { text: "Sustain A3 on 'oo' for 4 seconds. Then 'oh' for 4 seconds. Then 'ah' for 4 seconds. Then 'eh' for 4 seconds. Then 'ee' for 4 seconds. Same pitch, five different vowels. Notice which feel easiest and which feel hardest.", why: "At the passaggio, vowel choice dramatically affects ease of phonation because each vowel creates a different acoustic environment inside the vocal tract. The vocal tract is a resonating tube, and vowels change its shape — length, width, tongue position, lip rounding. These shape changes alter the formant frequencies (natural resonance peaks of the tube), which either help or hinder the vocal fold vibration at a given pitch. Rounded vowels (oo, oh) lower the larynx and widen the pharynx, which moves the first formant frequency away from the fundamental frequency at A3, reducing acoustic interference. Open vowels (ee, eh) do the opposite — they can bring formant and fundamental into conflict, creating the sensation of 'fighting through' the note." },
        { text: "Now sing G3-A3-Bb3 on 'oo.' Three notes through the passaggio on your easiest vowel. Smooth and connected. This should feel relatively easy — 'oo' is your passaggio ally.", why: "'Oo' naturally facilitates mix voice because it lowers the first formant and creates a rounded vocal tract that allows the vocal folds to thin out gradually. The passaggio crossing on 'oo' should feel almost effortless compared to what is coming. This easy success is not just a warm-up — it is establishing the FEELING of a smooth passaggio crossing so your brain has a target sensation to aim for when you try harder vowels. Motor learning research shows that the brain learns efficient patterns best when it has experienced the efficient version first. 'Oo' gives you that experience." },
        { text: "Same G3-A3-Bb3 on 'oh.' Slightly harder than 'oo' because 'oh' is a bit more open. Then 'ah' — noticeably harder. Notice where the difficulty increases. Rate each vowel 1-5 for ease of passaggio crossing.", why: "As vowels open up (from 'oo' toward 'ah'), the larynx tends to rise and the pharynx narrows, which increases acoustic resistance at the passaggio. The difficulty gradient you experience is your personal 'vowel spectrum' for the break zone. Most tenors find the order from easiest to hardest is: oo, oh, ah, ee, eh — but your personal order may differ slightly. Rating each vowel creates a quantified map of your vowel ease that you can track over time. As your passaggio technique improves, the ratings should converge — the hard vowels approaching the ease of the easy ones." },
        { text: "Try G3-A3-Bb3 on 'eh' and 'ee.' These are typically the hardest vowels for the passaggio. If you crack, that is data — not failure. Note exactly which pitch and which vowel caused the crack.", why: "Open, bright vowels fight the passaggio the most because they create formant/fundamental conflicts at passaggio pitches. Learning to cross smoothly on these vowels gives you complete vowel freedom in the break zone — the ability to sing any lyric at any passaggio pitch without worrying about which vowel is on which note. This freedom is what separates intermediate singers from advanced singers. The cracks you experience now are specific coordination failures that will resolve with targeted practice. Each crack tells your brain exactly what adjustment is needed, even if you cannot articulate that adjustment consciously. Your motor system processes the error and makes automatic corrections on subsequent attempts." },
        { text: "Repeat the full five-vowel sequence 3 times. On each pass, try to make the harder vowels feel more like the easy ones. Use this strategy: sing the easy vowel (oo), memorize the FEELING, then immediately sing the hard vowel (ee) while trying to maintain that same internal feeling.", why: "The 'transfer the feeling' strategy is a core technique in vocal pedagogy. The physical sensations of good resonance — forward buzz, open throat, relaxed jaw — are similar across all vowels when the technique is correct. By anchoring to the feeling of the easy vowel and carrying it into the hard vowel, you are giving your motor system a target. This is more effective than trying to intellectually analyze and correct the hard vowel because motor skills are learned through sensation, not cognition. Your brain cannot directly control the intrinsic laryngeal muscles — they respond to sensory targets and auditory images, not verbal instructions." },
        { text: "Now try a vowel migration: start G3 on 'oo,' sing A3 on 'oh,' sing Bb3 on 'ah.' You are changing vowel AND pitch simultaneously. This is what actual singing demands — every note potentially has a different vowel.", why: "Real songs never let you choose comfortable vowels for passaggio notes — the lyrics determine the vowel, and the melody determines the pitch. This exercise simulates that reality by pairing each passaggio pitch with a different vowel. The combined challenge of vowel change plus pitch change plus register transition is significantly harder than either challenge alone. But this is the real skill you need — navigating the passaggio on whatever vowel the song demands. If you can do this exercise smoothly, you can sing lyrics through the break without fear." },
        { text: "Reverse the vowel migration: start G3 on 'ah,' A3 on 'oh,' Bb3 on 'oo.' Now the hardest vowel is on the lowest note and the easiest is on the highest. Compare the difficulty to the previous ordering. Most singers find this version easier because the easiest vowel coincides with the highest (most challenging) note.", why: "This comparison demonstrates the power of vowel choice in managing the passaggio. When you pair the easy vowel with the hard pitch, the overall challenge decreases. In actual singing, you can sometimes apply this principle through vowel modification — subtly rounding or closing a vowel on a high passaggio note to make it easier. This is not 'cheating' — it is intelligent vowel management, and every trained singer does it. Opera singers are legendary for it (modifying 'ah' to 'aw' on high notes, for example), but pop and rock singers do it too, just more subtly." },
        { text: "Final challenge: sing the word 'yeah' on A3. This single word contains 'y' (ee), 'eh,' and 'ah' — three vowels in rapid succession, all on a passaggio note. If you can sing 'yeah' cleanly on A3, you are ready for real lyrics through the break.", why: "The word 'yeah' is a microcosm of the vowel challenge in real singing — multiple vowels in rapid succession on a single pitch. It is particularly diagnostic because all three vowels ('ee' glide, 'eh' body, 'ah' release) are among the harder passaggio vowels. Singing it cleanly on A3 requires the laryngeal muscles to maintain a stable register configuration while the articulators (tongue, jaw, lips) change shape rapidly for the vowel transitions. This is the coordination that singing lyrics demands, and it is exactly what this exercise trains. If 'yeah' on A3 sounds clean and free, your vowel formant shaping is working." }
      ],
      feel: "The easy vowels should feel like sliding through butter. The hard vowels will feel like a speed bump — a moment of resistance at A3. With practice, all vowels should approach the ease of 'oo.' The vowel migration exercises should feel like real singing — musical and expressive, not mechanical.",
      wrong: "If every vowel cracks at A3, you are probably using too much volume. Drop to a conversational 5/10 volume. The quieter you sing, the easier the crossing. If even quiet singing cracks, your passaggio may not be at A3 — go back to the diagnostic (v2e0) and confirm your break location. Some days the passaggio shifts a half step based on warm-up status.",
      sarah: "Vowel formant shaping is why opera singers modify vowels as they go higher. You do not need to sing opera, but the principle is the same — let the vowel help the voice, not fight it. The cool thing is, once you understand this, you start hearing it everywhere. Listen to Angus Stone singing through his break — those vowels are subtly rounded, helping the transition. Listen to the Allah-Las — the vowels are open and forward because they live below the break in pure chest voice. Vowel choice is a tonal tool, not just a pronunciation decision.",
      levelUp: "Smooth G3-A3-Bb3 crossing on all five vowels with no cracks, 3 consecutive passes. 'Yeah' on A3 sounds clean and free."
    },
    {
      id: "v2e4", time: 4, title: "Vowel Modification Climb — Full Ascent", type: "vocal",
      pitchContour: true,
      what: "Ascend E3-C4 shifting vowels as you climb: 'ah' in chest, 'uh' through the break, 'oh' in head. You are learning to modify vowels to smooth register transitions — applying the formant shaping from v2e3b in a climbing pattern that mirrors real melodic movement. This is the first exercise where technique serves melody rather than the other way around.",
      setup: "Standing. Pitch Detector on. Reference the vowel formant work from v2e3b.",
      referencePitches: getPitchRange("E3", "C4"),
      metronome: 70,
      recorder: true,
      steps: [
        { text: "Start on E3 with 'ah' — open chest vowel. Sing E3-F3-G3 on 'ah.' Should feel warm, full, and grounded. No effort, pure chest voice.", why: "Below the break, 'ah' is the natural, unmodified vowel. Your chest voice handles these notes easily with full vocal fold mass vibration. Starting here establishes the tonal baseline — this is what comfortable, well-supported chest voice sounds like. The warmth and fullness you feel is the large-amplitude vibration of the full vocal fold mass, resonating in the chest cavity. This is the sound of singers like Tommy Guerrero's vocals — low, warm, grounded. You are building from this foundation upward." },
        { text: "At Ab3, begin shifting from 'ah' toward 'uh.' The shift should be gradual — not a sudden switch but a slow rounding of the vowel. Sing Ab3 on a sound that is halfway between 'ah' and 'uh.' It should sound like 'ah' but feel slightly rounder.", why: "The vowel modification begins one half step before the passaggio to give the vocal tract time to adjust. Waiting until A3 to modify is too late — the register transition is already happening, and adding a vowel change on top of it overloads the system. By starting the modification at Ab3, you are preparing the vocal tract for the transition ahead. Think of it as downshifting before a hill rather than on the hill. The 'ah' to 'uh' modification lowers the first formant frequency, which reduces the acoustic load on the vocal folds at passaggio pitches, allowing them to thin out gradually rather than flipping abruptly." },
        { text: "At A3, you should be fully on 'uh.' Sing A3-Bb3 on 'uh.' Notice how much easier the passaggio feels with the modified vowel compared to singing 'ah' through the break (which you tried in v2e3b).", why: "The comparison is the lesson: 'ah' through the break feels like pushing through a wall. 'Uh' through the break feels like walking through a door. The vowel modification does not eliminate the register transition — it reduces the acoustic resistance, allowing the vocal fold muscles to negotiate the transition with less stress. This is not cheating; it is physics. The vocal tract and the vocal folds are a coupled system, and changing one (the tract shape via vowel) affects the other (the fold vibration pattern). Intelligent vowel modification is using this coupling to your advantage." },
        { text: "At Bb3, shift from 'uh' to 'oh.' Sing Bb3-B3-C4 on 'oh.' The tone should feel heady but supported — lighter than chest voice but not wispy. The 'oh' vowel keeps the larynx low and the throat open.", why: "'Oh' is a rounded, semi-closed vowel that works naturally with head/mix voice placement. It maintains enough laryngeal depression to prevent the 'squeezed' quality that 'ah' or 'eh' can produce above the break. The transition from 'uh' to 'oh' is subtle — both are rounded vowels with similar oral configurations. The main change is a slight lift of the soft palate and a forward shift of tongue position. On C4, you should feel the sound resonating in your face (forward placement) rather than your chest. This face resonance is the somatosensory marker of head/mix voice, and it should feel vibrant, not strained." },
        { text: "Now do the whole climb E3-C4 in one pass, shifting vowels at the right spots. Smooth, no gaps between vowels. The vowel changes should be inaudible to a listener — the tone color changes gradually, but no one should hear you 'switch' vowels.", why: "The integrated climb is where technique becomes music. In isolation, the vowel shifts are conscious and deliberate. In the full climb, they must become automatic — happening as a natural response to the ascending pitch rather than as a conscious decision. This automaticity is the associative stage of motor learning: you know the pattern and can execute it with attention, but it does not yet happen without thought. With daily practice over several weeks, the vowel modifications will become autonomous — your voice will automatically round vowels as you approach the passaggio, just as trained singers do. The inaudibility criterion is important: if a listener hears the vowel switch, it is too abrupt." },
        { text: "Descend: C4-B3-Bb3-A3-Ab3-G3-F3-E3, reversing the vowel modifications. 'Oh' at the top, 'uh' through the break, 'ah' at the bottom. The descent should feel like a release — the vowels opening up as the voice settles into chest voice.", why: "Descending vowel modification is easier than ascending because the vowels are opening up (from closed 'oh' to open 'ah'), which aligns with the natural tendency of the voice as it descends — the vocal folds are thickening and the chest cavity is resonating more strongly, both of which pair naturally with more open vowels. Practicing both directions ensures the skill is bidirectional, which is essential for real songs where melodies rise and fall unpredictably. A singer who can only modify vowels ascending but not descending has a one-way passaggio, which limits their melodic freedom." },
        { text: "Speed it up: do the full climb at 90 BPM instead of 70. The vowel modifications must happen faster, which challenges the automaticity of the skill. If the faster tempo causes the vowel shifts to break down, slow back to 70 and practice more before attempting 90 again.", why: "Increasing tempo is the standard motor learning challenge for testing skill robustness. A skill that works at 70 BPM but fails at 90 BPM is not yet fully learned — it is still in the cognitive or early associative stage. The tempo increase forces the motor system to execute the vowel modifications with less conscious processing time, pushing toward automaticity. The tempo at which the skill breaks down is your 'current speed limit' — practice at that tempo and slightly below it for optimal learning, then test at higher tempos periodically. This is the same approach used in training musicians, athletes, and surgeons." },
        { text: "Musical application: sing the climb on the word 'home' — 'ho-oh-oh-oh-ome.' The natural vowel of the word starts rounded ('oh') and opens to a nasal close ('m'). Distribute the syllable across the ascending pitches E3-C4. This is how vowel modification works in actual lyrics — the word shapes the sound, and you adjust within the word.", why: "Applying the technique to an actual word demonstrates that vowel modification is not an abstract exercise — it is a real-time singing skill. The word 'home' is well-suited because its natural vowel progression (from open 'h' to rounded 'oh' to nasal 'm') partially aligns with the modification pattern you have been practicing. In actual songs, you will encounter less convenient words on passaggio notes, but the principle is the same: let the vowel help the voice by finding the roundest, most supportive version of whatever vowel the lyric demands. 'Home' on an ascending line should sound warm, present, and effortless — the kind of sound you hear in DOPE LEMON's laid-back melodies." }
      ],
      feel: "Each vowel change should feel like a natural adjustment, not a sudden switch. Like changing gears in a car — smooth and continuous. The full climb should feel like one continuous sound that changes color gradually from warm and full (bottom) to bright and present (top).",
      wrong: "If the vowel changes sound abrupt, you are switching too suddenly. Overlap the vowels: 'ah' gradually morphs into 'uh,' which gradually morphs into 'oh.' If you hear distinct vowels, the transitions are too sharp. If the climb cracks despite the vowel modifications, your volume is too high — reduce to 5/10.",
      sarah: "Vowel modification is one of those skills that sounds technical but is actually completely natural. When you sing along to your favorite songs in the car, you are already modifying vowels — you just do not know it. This exercise makes the unconscious conscious so you can do it deliberately when you need it. Once it becomes automatic again (conscious → unconscious competence), you will not even think about it. Your voice will just... handle the break. That is the goal.",
      metronome: 70,
      levelUp: "Smooth ascending climb E3-C4 with inaudible vowel modifications and no audible break, 3 times. Descending climb equally smooth."
    },
    {
      id: "v2e5", time: 4, title: "Ooh Climbing Over Chords", type: "vocal",
      pitchContour: true,
      what: "Over a chord progression, sing 4 ascending 'ooh' notes per chord. Each chord gets different notes. Push through the break zone as you repeat cycles. This bridges the gap between technical exercises and real singing — you are improvising melodies in real-time over a harmonic framework, which is exactly what singing a song demands.",
      setup: "Guitar: Am -> C -> G -> D. Island strum or fingerpick at 120 BPM. Or use a backing track.",
      referencePitches: getPitchRange("A2", "C4"),
      metronome: 120,
      recorder: true,
      tracks: [{ name: "Reggae One Drop 85", src: "/reggae-one-drop-85.mp3" }],
      steps: [
        { text: "On Am: sing 4 'ooh' notes that CLIMB within the chord. Example: A2-C3-E3-A3. Each note falls on a downbeat. Let the 'ooh' vowel carry you upward with rounded, relaxed sound.", why: "Climbing on chord tones connects pitch accuracy to harmonic awareness — you are not just singing notes in a scale but hearing how specific pitches relate to the underlying harmony. A2 is the root of Am, C3 is the minor third, E3 is the fifth, A3 is the octave. These intervals define the chord, and singing them ingrains the sound of the Am triad in your ear. This kind of ear training through singing is dramatically more effective than passive listening because it engages the auditory-motor loop: your brain must predict the pitch, execute it, and verify the result against the chord. The 'ooh' vowel is chosen because it is the easiest passaggio vowel, giving you maximum vocal ease while the cognitive challenge (hearing chord tones) is high." },
        { text: "On C: sing 4 DIFFERENT climbing notes. Example: C3-E3-G3-C4. These are C major chord tones. The top note (C4) pushes you above the break.", why: "Forcing different patterns on each chord prevents autopilot — the enemy of deliberate practice. If you sing the same four notes on every chord, your brain learns a pattern, not a skill. By choosing chord-appropriate notes for each chord, you are training harmonic awareness simultaneously with pitch accuracy and passaggio navigation. The C4 at the top of the C major arpeggio takes you above the break, which means you must navigate the passaggio while also tracking the harmonic context. This dual challenge mirrors real singing perfectly." },
        { text: "On G and D: keep climbing, keep changing the pattern. G might be G2-B2-D3-G3. D might be D3-F#3-A3-D4. Each chord gets its own ascending path.", why: "The variety forces your ear to find new paths through the harmony. D4 on the D chord takes you well above the break, into solid head/mix territory. If you crack on D4, that is fine — it tells you the upper limit of your current comfortable range. Sarah's philosophy: a committed crack teaches your voice more than a safe whisper. The crack is your brain's motor system receiving error feedback that it will use to improve on the next attempt. Avoiding the crack by staying safe prevents this learning signal from reaching your motor cortex." },
        { text: "As you repeat cycles, push the range higher each time. First cycle: top out at A3. Second cycle: top out at Bb3. Third cycle: push to C4 or D4. Let yourself enter the break zone progressively.", why: "Progressive range expansion is safer and more effective than immediately singing at your upper limit. Each cycle pushes you a half step further, giving the vocal folds time to adjust to the increasing stretch. This graduated approach follows the overload principle from exercise science: stress the system slightly beyond its current capacity, allow it to adapt, then increase the stress again. Jumping to D4 on the first cycle would likely produce a crack with no learning benefit. Building up to it over several cycles produces a crack (if it happens) at the frontier of your ability, where the learning benefit is maximized." },
        { text: "COMMIT to each note. More air = better pitch. Do not retreat into breathy, tentative singing when you approach the break zone. Push the air, engage the diaphragm, and let the voice figure out the coordination.", why: "Sarah's most frequent instruction, and the most counterintuitive for new singers. The instinct when approaching the break is to get quieter and breathier, hoping to sneak through the transition. But breathy singing at the passaggio actually makes the crack MORE likely because the vocal folds are not fully adducting (closing), leaving gaps that create turbulent airflow and unstable vibration. More air means more subglottic pressure, which means more vocal fold contact, which means more stable vibration — even in the break zone. Commitment is not about volume; it is about full engagement of the breath support system. A committed mf in the break zone is more stable than a tentative pp." },
        { text: "Now vary the vowel: instead of all 'ooh,' try climbing on 'oh' for one cycle, then 'ah' for one cycle. Notice how the break becomes more challenging on the more open vowels, just as it did in v2e3b.", why: "Applying the vowel formant knowledge from earlier in a musical context reinforces the connection between technique and performance. In a real song, you cannot choose 'ooh' for every passaggio note — the lyrics determine the vowel. By practicing the climbing exercise on multiple vowels, you build the ability to navigate the break regardless of vowel, which is the functional skill you need. The comparison also provides real-time feedback on your vowel formant progress: if 'ah' is getting easier over the weeks, your passaggio technique is genuinely improving, not just improving on easy vowels." },
        { text: "Musical challenge: instead of straight chord tones, improvise a melodic line over each chord. Not just climbing — use steps, skips, and repeated notes. Make it sound like a melody, not an exercise. The 'ooh' becomes 'ooh-ooh-ooh-ooh' with melodic shape.", why: "This transitions from technical exercise to creative expression. Improvising melodies over chords is what singers do in real-time during performance — choosing pitches, shaping phrases, navigating range. By doing it on 'ooh,' you maintain the vocal ease while engaging your musicality. The melodies you improvise will reflect your musical influences — the Khruangbin-style minimalism, the reggae-rock phrasing, the desert-blues intervals. Let your taste guide the melodic choices. If a particular melodic idea pushes you through the break, all the better — you are training passaggio navigation in a musically authentic context." }
      ],
      feel: "This should feel like musical exploration — you are improvising melody in real-time over a chord progression. When you enter the break zone, the voice may thin out or crack. That is the exercise working. The 'ooh' should feel warm and round, even at higher pitches.",
      wrong: "If you sing the same 4 notes on every chord, you are on autopilot. Force yourself to start on different notes, use different intervals. If you retreat to breathy, uncommitted singing near the break, remind yourself: commit. More air, more support, more intention. Safe singing teaches nothing.",
      sarah: "Commit is the word. Soft, breathy singing in the break zone just makes the folds unable to phonate cleanly. Push the air, let the voice figure it out. I would rather hear a confident crack than a perfect breathy avoidance. The crack means you are actually working the passaggio. The breathy avoidance means you are hiding from it. Which one do you think leads to improvement?",
      levelUp: "Regularly entering break zone with committed tone across all 4 chords. Improvised melodies sound musical rather than mechanical."
    },
    {
      id: "v2e6", time: 4, title: "Rhythmic Pitch Matching — Accuracy Under Pressure", type: "vocal",
      what: "Over a groove beat with Am on guitar, sing specific chord tones on specific beats. Then move them to off-beats. This fuses pitch training with rhythm training, simulating the dual demands of real singing where you must be in tune AND in time simultaneously. The cognitive load of rhythm tracking reveals whether your pitch accuracy is truly internalized or requires conscious attention.",
      setup: "Guitar: Am chord. Groove Beat 90 BPM playing.",
      referencePitches: getPitchRange("A2", "C4"),
      tracks: [{ name: "Groove Beat 90", src: "/groove-beat-90.mp3" }],
      metronome: 90,
      recorder: true,
      steps: [
        { text: "Sing Am chord tones: Root (A2) on beat 1, minor 3rd (C3) on beat 3. Just these two notes, landing precisely on beats 1 and 3. Rest on beats 2 and 4.", why: "Placing specific pitches on specific beats is the fundamental coordination of singing. In isolation, pitch accuracy and rhythm accuracy are both manageable. Together, they compete for cognitive resources — your brain must simultaneously predict the pitch (auditory-motor loop), execute it (laryngeal muscles), and time it (motor timing circuits). Starting with just two notes on strong beats minimizes the cognitive load while establishing the coordination. Beats 1 and 3 are the strongest metrical positions, making them the easiest targets. The pitch detector and your ear both confirm accuracy, giving your brain two feedback channels to calibrate against." },
        { text: "Next bar: 5th (E3) on beat 1, Octave (A3) on beat 3. Notice: A3 is in the break zone — you are training passaggio while thinking about rhythm.", why: "A3 on beat 3 introduces the passaggio challenge within a rhythmic context. When your brain is occupied with beat tracking, the vocal fold adjustments for A3 must happen more automatically. If A3 cracks when you are thinking about rhythm but does not crack in isolation, that tells you the passaggio skill is still in the cognitive stage — it requires conscious attention to execute. The goal is to push it to the associative and eventually autonomous stage, where the passaggio crossing happens automatically regardless of what else you are doing. Dual-task exercises like this one are the primary tool for testing and building automaticity." },
        { text: "Descend back down over 2 bars: A3 on beat 1, E3 on beat 3, then C3 on beat 1, A2 on beat 3. You have now traced a full Am arpeggio up and down over 4 bars.", why: "The full arpeggio combines ascending and descending passaggio crossings with harmonic awareness and rhythmic precision. It is a miniature song — pitch, time, and harmony working together. The descending pattern crosses back through the break zone (A3 to E3) which, as you know from v2e1, is typically easier than ascending. If the descent is smoother than the ascent, that asymmetry is your training target." },
        { text: "Repeat the same pattern for C major: C3 on beat 1, E3 on beat 3, G3 on beat 1, C4 on beat 3. Then G major and D major. Each chord gets the same ascending-descending arpeggio pattern.", why: "Tracking chord tones through different chords while maintaining rhythmic precision simulates actual singing over a chord progression. The pitch targets change with each chord, requiring your auditory-motor loop to retarget. The rhythm stays constant, allowing the beat-tracking to become automatic. This combination of variable pitch with stable rhythm is exactly what happens in a verse — the chords change underneath you while the rhythmic feel stays consistent. The C4 on the C chord and the D4 on the D chord push you into the upper break zone, challenging passaggio navigation in a musical context." },
        { text: "LEVEL UP: Move the notes to the &'s instead of the beats. Same pitches: A2 on the & of beat 1, C3 on the & of beat 3. This syncopated placement adds rhythmic complexity to the pitch accuracy challenge.", why: "Syncopation — singing between the beats instead of on them — is the rhythmic vocabulary of reggae, soul, funk, and virtually all the genres you love. The Allah-Las, Khruangbin, and reggae artists all use syncopated vocal placement extensively. Placing pitch targets on off-beats requires your rhythm-tracking system to maintain the downbeat internally while your voice acts on the upbeat. This is the same skill trained in Level 3 (rhythm), but here it is combined with pitch accuracy training. The dual challenge reveals whether either skill degrades when paired with the other." },
        { text: "Try the syncopated version through all 4 chords. If your pitch accuracy drops when you add syncopation, that tells you the pitch skill needs more automation before it can coexist with rhythmic complexity. Practice the on-beat version more before returning to syncopation.", why: "The degradation test is how motor learning researchers assess skill automaticity. If Skill A (pitch accuracy) degrades when Skill B (syncopated rhythm) is added, Skill A is not yet automatic — it still requires conscious attention that syncopation steals. The solution is more practice of Skill A in isolation (pitch exercises from earlier in this level) until it reaches a level of automaticity where it can survive the addition of rhythmic complexity. This is not a failure — it is a normal and expected phase of learning. Dual-task performance improves as individual skills become more automatic." },
        { text: "Creative extension: over the Am chord with the groove beat, improvise a vocal line using Am pentatonic notes (A-C-D-E-G) placed anywhere in the bar — on beats, off beats, or between beats. Let it be musical. Sing on 'ooh' or 'doo.' This is free improvisation within a harmonic and rhythmic framework.", why: "Free improvisation is the destination that all these technical exercises are building toward. Improvising a vocal line requires pitch accuracy (hitting pentatonic scale tones), rhythmic feel (placing notes in the groove), passaggio navigation (some pentatonic notes are in the break zone), and musicality (making it sound intentional and expressive). If you can improvise musical-sounding phrases over a groove, all the skills in this level are coming together. The pentatonic scale is particularly well-suited because it has no 'wrong' notes over Am — every combination sounds good, freeing you to focus on delivery rather than note choice." }
      ],
      feel: "On-beat version should feel like 'placing' notes on a shelf — deliberate and precise. The syncopated version should feel like the notes are floating between the beats — laidback and groovy. The improvisation should feel like play — musical exploration without performance pressure.",
      wrong: "If you are hitting approximately-right pitches, play the target note on guitar first, listen, then sing it. Pitch memory improves with exact reference points. If rhythm and pitch are both degrading, simplify: go back to two notes on beats 1 and 3 until both feel solid, then add complexity.",
      sarah: "When you sing A3 on beat 3 of bar 2, you are singing in your break zone while tracking a rhythm. This is intentional — it trains you to navigate the passaggio while thinking about something else. In a real song, you are thinking about lyrics, emotion, guitar chords, and audience connection. If your passaggio only works when you are concentrating entirely on your voice, it is not ready for performance. These dual-task exercises make it ready.",
      levelUp: "Clean syncopated version with accurate pitches on all 4 chords. Free improvisation sounds musical and navigates the break zone without retreating to safe notes."
    },
    {
      id: "v2e7", time: 4, title: "Eyes-Closed Pitch Matching — Training the Forward Model", type: "vocal",
      what: "Remove all visual crutches — no pitch detector, no guitar fret reference, no sheet music. Close your eyes and match pitches using only your ears and your body's internal sense of pitch. This trains the auditory-motor loop's 'forward model' — your brain's ability to predict and produce a target pitch without external verification.",
      setup: "Standing. Eyes closed. Someone plays random notes on guitar, or use a pitch generator app set to random notes in E3-C4 range. Pitch detector OFF during the exercise (turn it on only to verify afterward).",
      referencePitches: getPitchRange("E3", "C4"),
      recorder: true,
      steps: [
        { text: "Have a reference pitch played: any note between E3 and C4 (you do not know which one in advance). Listen for 2 seconds with eyes closed. Do NOT look at a tuner or fretboard. Then sing the note back on 'ah.' Hold for 3 seconds.", why: "Eyes-closed pitch matching isolates the auditory-motor loop from all external assistance. When the pitch detector is on, your brain can use visual feedback to correct pitch in real-time — you see the needle drift flat and adjust. This is useful for building the motor pattern, but it can become a crutch. With eyes closed and no visual feedback, your brain must rely entirely on its internal forward model: the neural prediction of what pitch your voice will produce based on the motor commands it sends to the laryngeal muscles. If the forward model is accurate, you match the pitch effortlessly. If it is inaccurate, you hear the mismatch and your brain begins updating the model. This self-correction is the mechanism of pitch improvement." },
        { text: "After singing the note, open your eyes and check the pitch detector. Were you sharp, flat, or accurate? Note the direction and magnitude of the error. Close eyes and try again with a new random note.", why: "The delayed feedback protocol — attempt first, check after — is the most effective method for training the forward model. Immediate visual feedback (watching the tuner while you sing) teaches your brain to rely on external correction. Delayed feedback (checking after the attempt) teaches your brain to rely on internal prediction. Research on motor learning consistently shows that delayed feedback produces slower initial improvement but better long-term retention and transfer compared to immediate feedback. You are trading short-term accuracy for long-term skill development." },
        { text: "Do 10 random notes. Track your accuracy: how many were within a quarter-tone of the target? How many were within a half-step? How many were off by more than a half-step? This is your pitch-matching accuracy score.", why: "Quantifying accuracy turns a vague skill ('am I getting better at pitch?') into a measurable metric ('I matched 6 out of 10 within a quarter-tone last week and 7 out of 10 this week'). The quarter-tone threshold is the standard for 'in tune' in contemporary music — listeners perceive notes within a quarter-tone of the target as 'in tune' and notes more than a quarter-tone off as 'out of tune.' Half-step accuracy is the minimum threshold for recognizable melody. Tracking this score weekly gives you objective evidence of improvement that is independent of subjective feelings about your singing." },
        { text: "Identify your error pattern: do you consistently go sharp, consistently go flat, or randomly both? Most untrained singers have a consistent bias. Knowing yours lets you compensate deliberately.", why: "Systematic pitch bias reveals a miscalibration in the forward model. Consistently going sharp means your brain overestimates the muscle tension needed for each pitch — it sends commands for a higher pitch than intended. Consistently going flat means the opposite — underestimation. Random errors suggest the forward model is not yet calibrated at all and is essentially guessing. The bias direction matters for correction: if you know you tend flat, you can aim slightly higher, and over time this conscious compensation recalibrates the unconscious forward model. This is the same principle used in sports — a golfer who consistently hooks left aims right until the swing naturally straightens out." },
        { text: "Passaggio-zone challenge: have the reference play only notes between Ab3 and Bb3 — your break zone. Eyes closed, match 5 notes in this narrow range. These are the hardest to match because the vocal fold configuration is unstable in the transition zone.", why: "The passaggio zone is where pitch accuracy degrades most because the vocal folds are negotiating a register transition while also trying to hit a specific frequency. It is like trying to hit a bullseye while standing on a moving platform. The forward model has to account not just for the target pitch but also for the register configuration needed to produce it — a pitch in the passaggio can be produced by either a stretched chest voice or a thickened head voice, and the two configurations sound and feel different. Your brain must decide which configuration to use AND calibrate the muscle tension for the target pitch, all before the sound begins. This dual decision is why passaggio pitch accuracy requires dedicated training." },
        { text: "Micro-pitch challenge: have a reference note played, then try to sing it exactly one quarter-tone sharp. Then exactly one quarter-tone flat. Then back to the exact pitch. This trains pitch granularity — your ability to control pitch in increments smaller than a half-step.", why: "Quarter-tone control is the frontier of pitch accuracy training. Most Western music uses half-step intervals, but expressive singing requires micro-pitch adjustments — the slight sharpening at the top of a phrase for excitement, the slight flattening for a bluesy feel, the vibrato that oscillates around the target pitch. The music you love is full of micro-pitch expression: Tinariwen's desert-blues melodies use quarter-tones as ornaments, reggae vocals often sit slightly behind the pitch for a relaxed feel, and psychedelic music plays with tuning as an expressive tool. Training quarter-tone control gives you access to these expressive micro-adjustments, which are what make singing sound human rather than robotic." },
        { text: "Final test: eyes closed, have 5 random notes played in sequence (like a short melody), then sing the entire sequence back from memory. This tests pitch memory — your ability to hold multiple pitches in your auditory working memory.", why: "Pitch memory is the foundation of learning songs by ear — you must hear a melody, hold it in memory, and reproduce it vocally. The auditory working memory system typically holds 4-7 items (similar to digit span), and each pitch occupies one slot. Five notes is a reasonable challenge that tests the system without overwhelming it. If you can accurately reproduce a 5-note melody by ear, you have the pitch memory capacity needed for learning songs efficiently. If you struggle with 5, practice with 3 and build up. This skill improves rapidly with practice because it uses the same auditory-motor loop you have been training in every exercise — you are just adding a memory component." },
        { text: "Open your eyes. Turn the pitch detector back on. Sing an ascending scale from E3 to C4 while watching the detector. Notice how much easier it feels with visual feedback compared to eyes-closed matching. The difference between these two experiences is the gap that training is closing.", why: "The final comparison demonstrates the current role of visual feedback in your pitch accuracy. If the eyes-open scale feels dramatically easier than the eyes-closed matching, your forward model still relies heavily on external feedback. If the difference is subtle, your forward model is becoming self-sufficient. Over weeks of practice, the eyes-closed accuracy should approach the eyes-open accuracy, indicating that the forward model has internalized the pitch-to-motor mapping. When eyes-closed matching feels as natural as eyes-open matching, you have achieved the internalized pitch accuracy that makes singers sound 'naturally gifted.' It is not a gift — it is a trained neural circuit." }
      ],
      feel: "Eyes-closed matching should feel slightly uncomfortable and uncertain at first — you are flying without instruments, trusting your internal sense. The discomfort is the learning. Over time, it should feel increasingly natural, as the forward model gains accuracy and confidence.",
      wrong: "Do NOT peek at the tuner while singing — that defeats the entire purpose. The exercise only works if you commit to checking AFTER the attempt. If you find the random notes too hard, start with a known note: play C3 yourself, look away, and match it. Then close your eyes and have someone else play notes. Build up to fully random gradually.",
      sarah: "This exercise is where pitch accuracy really lives. Anyone can sing in tune while watching a tuner — that is like driving with GPS. But can you drive without GPS? Can you get where you are going based on your internal map? Eyes-closed pitch matching builds that internal map. And here is the beautiful thing: once the internal map is accurate, you never lose it. It becomes a permanent part of your neural wiring. Pitch accuracy is not something you were born with or without — it is a trainable skill, and this is how you train it.",
      levelUp: "Match 7 out of 10 random notes within a quarter-tone accuracy, eyes closed. Reproduce a 5-note melody from memory with at least 4 correct pitches."
    },
    {
      id: "v2e8", time: 4, title: "Passaggio Mapping Journal — Know Your Instrument", type: "vocal",
      what: "A structured self-assessment that maps the current state of your passaggio in detail. Where exactly is your break? How wide is the transition zone? Which vowels are easiest and hardest? Which direction (ascending/descending) is smoother? This journal entry creates a personalized reference that guides your daily practice focus and tracks changes over weeks of training.",
      setup: "Standing. Pitch detector on. Pen and paper (or phone notes). This exercise combines singing with reflection and documentation.",
      recorder: true,
      referencePitches: getPitchRange("F3", "C4"),
      steps: [
        { text: "Ascending slide on 'ooh' from F3 to C4. Listen and feel for the exact note where the voice first shows any change in quality — even subtle warmth-to-brightness shift. Write down: 'First sign of transition: [note].' This is the bottom of your passaggio zone.", why: "The passaggio is not a single note but a zone — typically spanning 2-4 half steps. The bottom of the zone is where the vocal folds first begin to thin out from their full chest-voice configuration. This may be as low as G3 or as high as A3, and it can change day to day based on warm-up status, hydration, and fatigue. Mapping the bottom boundary gives you advance warning in real singing: when you see a melody approaching that note, you can prepare by adjusting your breath support and vowel shape. This preparation prevents surprise cracks." },
        { text: "Continue the slide. Find the note where the transition is most pronounced — the 'center' of the break, where the voice is most likely to crack or flip. Write down: 'Break center: [note].' For most tenors, this is A3 or Bb3.", why: "The break center is where the vocal folds are in their most ambiguous configuration — neither fully chest nor fully head. At this note, the slightest change in subglottic pressure, vowel shape, or laryngeal tension can flip the voice from one register to the other. This is the pitch where your messa di voce (v2e2) is most challenging and most educational. Knowing your exact break center — not approximately, but to the specific note — lets you target your passaggio exercises with surgical precision. Generic passaggio exercises work, but targeted exercises at YOUR break center work three times faster." },
        { text: "Find the note where the transition completes — where the voice settles into stable head/mix with no remaining instability. Write down: 'Transition complete: [note].' This is the top of your passaggio zone.", why: "The top of the passaggio zone is where the vocal folds have fully transitioned to their thin, stretched configuration. Above this note, the voice is in stable head/mix register and the instability disappears. For most tenors, this is B3 or C4. The width of your passaggio zone (from bottom to top) indicates the 'width of the crack' — a narrow zone (2 half steps) means the transition happens quickly, while a wide zone (4 half steps) means the transition is gradual. Both have advantages: a narrow transition is easier to manage but more abrupt; a wide transition is harder to manage but smoother when done well." },
        { text: "Test each vowel at your break center note: 'oo,' 'oh,' 'ah,' 'eh,' 'ee.' Rate each 1-10 for stability (10 = perfectly smooth, 1 = immediate crack). Write down all five ratings. Identify your easiest and hardest vowels.", why: "The vowel stability map is your personal cheat sheet for singing lyrics through the passaggio. When learning a new song, you can look at which vowels fall on passaggio notes and predict where you will have trouble. If the word 'never' falls on your break center note, and 'eh' is your weakest vowel, you know that word needs extra practice. This kind of strategic preparation is how professional singers learn new material quickly — they identify the danger zones (passaggio notes + hard vowels) and practice those spots first, rather than running the whole song over and over and hoping the problem spots improve by accident." },
        { text: "Test ascending vs. descending smoothness: sing G3-A3-Bb3-B3 on 'ooh' (ascending through break), then B3-Bb3-A3-G3 (descending). Rate each direction 1-10 for smoothness. Write down which direction is smoother and by how much.", why: "The directional asymmetry tells you which motor pattern needs more work. If ascending is significantly harder than descending (the most common pattern), your cricothyroid muscle (which stretches the folds for ascending pitch) needs more training in the passaggio zone. If descending is harder (less common), the thyroarytenoid muscles are not releasing smoothly. Most singers develop a comfort-direction first and then work on the other. Knowing your asymmetry lets you allocate practice time efficiently: spend more time on the harder direction until the smoothness ratings equalize." },
        { text: "Volume test at break center: sing your break center note at pp, mp, mf, and f. Rate each volume level for stability. Write down the volume at which stability first degrades. This is your 'volume ceiling' in the passaggio.", why: "Every passaggio has a volume ceiling — the dynamic level above which the register transition becomes unmanageable. For most Level 2 students, this ceiling is mp or mf. Above the ceiling, the increased subglottic pressure forces the vocal folds into chest voice configuration, causing a crack. Below the ceiling, the folds can negotiate the transition smoothly. Knowing your ceiling sets your practice volume for passaggio exercises — always work at or slightly below the ceiling, not above it. As your technique improves, the ceiling rises. Tracking the ceiling over weeks gives you one of the clearest metrics of passaggio development." },
        { text: "Write a one-paragraph summary: 'My passaggio zone is from [bottom note] to [top note], centered on [center note]. My easiest vowel is [vowel] and my hardest is [vowel]. [Ascending/Descending] is smoother. My volume ceiling is [dynamic level].' Save this with today's date.", why: "The written summary is your personal vocal profile at this moment in time. It captures everything you need to know about your passaggio to practice effectively. Reviewing this summary before each practice session reminds you of your specific targets. Updating it every 2-3 weeks creates a longitudinal record of your development. Most students are surprised at how quickly the numbers change — the passaggio zone often narrows, the vowel ratings converge, and the volume ceiling rises within 2-4 weeks of daily practice. This objective progress data is motivating in a way that subjective feelings about singing quality can never be." },
        { text: "Based on your mapping, choose ONE area to focus on in your daily practice for the next week: your hardest vowel at the break center, your weaker direction (ascending or descending), or your volume ceiling. Focused practice on a single weakness produces faster improvement than general practice on everything.", why: "This is the principle of deliberate practice applied to vocal training. Deliberate practice requires: (1) identifying a specific weakness, (2) designing practice that targets that weakness, (3) receiving feedback on each attempt, and (4) repeating until improvement is measurable. The passaggio map gives you the data for step 1. The exercises in this level provide the methods for step 2. The pitch detector and recorder provide step 3. And the next mapping session (in 2-3 weeks) provides step 4. This cycle of map-practice-re-map is the engine of vocal development. It is not exciting, but it is extraordinarily effective." }
      ],
      feel: "This exercise should feel like a scientist studying a fascinating specimen — your own voice. The analytical approach removes emotional judgment. You are not 'good' or 'bad' at the passaggio — you have specific, measurable characteristics that respond to specific, targeted training. This mindset is powerful.",
      wrong: "Do not skip the writing. The map only works if you document it. Your memory of how things felt is unreliable — two weeks from now, you will not remember whether 'eh' was a 6 or a 7 at the break center. Write it down. Also: do not cherry-pick your best attempts for the ratings. Rate your average performance, not your best. The map should reflect your typical state, not your peak state.",
      sarah: "This is my favorite exercise in the whole curriculum because it turns something emotional and scary — the passaggio — into data. Data is not scary. Data is just information. And information leads to improvement. The students who improve fastest are not the most talented — they are the most analytical. They know exactly what their voice does and exactly what they are working on. Be that student. Map your passaggio. Train your weaknesses. Re-map. Repeat.",
      levelUp: "Completed passaggio map with all measurements documented. Identified one specific focus area for the coming week. You have a clear, data-driven understanding of your passaggio."
    },
    {
      id: "v2e9", time: 4, title: "Level 2 Integration — Musical Application", type: "vocal",
      pitchContour: true,
      recorder: true,
      what: "Apply everything from Level 2 to actual music. Sing a simple melody that passes through your passaggio — using the vowel modification, breath support, and register blending skills you have been building. This is where exercises become singing. Choose a phrase from a song you love that crosses the break, and sing it with full technique.",
      setup: "Guitar: simple chord progression in Am (Am-C-G or Am-F-C-G). Or use a backing track. Pitch detector on for verification but eyes on the music, not the screen.",
      referencePitches: getPitchRange("E3", "C4"),
      tracks: [
        { name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" },
        { name: "Desert Blues 75", src: "/desert-blues-75.mp3" },
        { name: "Dub Reggae 85", src: "/dub-reggae-85.mp3" }
      ],
      steps: [
        { text: "Choose a simple vocal melody that crosses your passaggio. It could be a melody from an Allah-Las song, a Khruangbin hum, or even something you make up. The only requirement: it must include at least one note above A3 and one below G3. Sing it on 'ooh' first, focusing on smooth passaggio crossing.", why: "Starting on 'ooh' removes the complication of lyrics, letting you focus entirely on the passaggio crossing in a musical context. The melody you choose should feel natural and appealing — this is not an exercise anymore, it is music. The emotional engagement of singing something you genuinely enjoy activates different neural circuits than mechanical exercises, and the motor learning that occurs during emotionally engaged practice is more durable. Your brain prioritizes skills that matter emotionally, so singing music you love literally trains faster than singing exercises you endure." },
        { text: "Now add lyrics. Sing the same melody with the actual words. Notice where the vowels in the lyrics make the passaggio easier or harder. Use the vowel modification principles from v2e4: let hard vowels round slightly as they approach the break.", why: "The transition from 'ooh' to lyrics is where technique meets reality. Some lyrics will place easy vowels on passaggio notes by coincidence, and those spots will feel effortless. Others will place 'ee' or 'eh' right on A3, creating a challenge. The vowel modification skill allows you to subtly adjust the pronunciation — not enough for a listener to hear the change, but enough for your vocal folds to navigate the transition. This is the skill that trained singers use constantly and unconsciously. You are training it consciously now so it becomes unconscious later." },
        { text: "Sing the melody over a backing track (Khruangbin Style 80, Desert Blues 75, or Dub Reggae 85 — pick the vibe that fits). Let the groove carry you. Singing with a track adds the rhythmic constraint that exercises lack.", why: "Backing tracks simulate performance conditions: you must maintain pitch accuracy, passaggio technique, vowel modification, AND rhythmic alignment simultaneously. This is the highest cognitive load in the curriculum so far, and it reveals how automated your skills really are. If everything falls apart when you add the track, some skills still need more isolated practice. If it mostly holds together with occasional wobbles, you are ready to start Level 3. The specific backing tracks are chosen to match the genres you love — they should feel inspiring, not intimidating. Music should always feel like play, even when it is practice." },
        { text: "Record yourself singing the melody with lyrics over the backing track. Play it back. Listen for: (1) pitch accuracy, especially near the passaggio, (2) smooth register transition or audible crack, (3) breath support — can you hear gasping between phrases? (4) tone quality — does it sound natural or strained?", why: "The four-criteria self-assessment develops your critical listening skills in a structured way. Without criteria, listening to yourself singing can trigger emotional reactions ('I sound terrible' or 'that was great!') that are not actionable. With specific criteria, you can make targeted observations: 'My pitch was accurate except on the A3 in bar 3, where I went flat. The transition cracked once on the word forever. My breathing was silent. My tone was natural until I reached B3, where it got tight.' These specific observations lead directly to specific practice targets. This is the feedback loop that drives improvement: perform, assess, identify targets, practice targets, perform again." },
        { text: "Compare this recording to your Level 2 diagnostic (v2e0). Listen to them back to back. The diagnostic was your unprocessed voice singing scales. This recording is your voice singing music with technique. The difference — even if subtle — represents the skills you have built in Level 2.", why: "The comparison is the most motivating moment in the curriculum so far. Your diagnostic recording captured a voice that did not yet know how to navigate the passaggio, modify vowels, or use breath support for pitch stability. Your Level 2 integration recording captures a voice that has been trained in all of these skills. The difference may be dramatic or subtle depending on how long you have been practicing, but it will be audible. This audible progress is the reward for all the analytical, methodical work of Level 2. You have earned it." },
        { text: "Improvise freely over the backing track for 2 minutes. No plan, no specific pitches, no rules. Sing 'ooh,' 'ah,' words, nonsense syllables — whatever comes out. Let yourself explore the full range including the passaggio. This is play.", why: "Free improvisation after structured practice integrates all skills in the most natural way — by not thinking about them. When you stop trying to execute techniques and just sing, your body reveals which skills have become automatic and which still need work. The automatic skills will show up effortlessly in your improvisation. The non-automatic skills will either be avoided (your voice stays below the passaggio) or fail (cracks when you venture into the break). Both observations are useful. Free improvisation also connects you to the joy of singing, which is the reason you are doing all of this in the first place. Never lose the play." },
        { text: "End by singing the first phrase of 'Happy Birthday' one more time — the same benchmark from Level 1's diagnostic. Notice how different it feels now. Your posture is aligned, your breath is supported, your resonance is placed, and your voice moves through the range with awareness and control. This is the Level 2 you.", why: "The 'Happy Birthday' bookend connects your Level 2 work to your Level 1 starting point, creating a narrative arc of progress. The same melody that felt unremarkable in the Level 1 diagnostic should now feel richer — more supported, more resonant, more controlled. You are not singing it better because you practiced 'Happy Birthday.' You are singing it better because you have fundamentally improved the instrument. This is the power of foundational training: it improves everything, not just the specific exercises you practiced. Every song you sing from now on benefits from the work you did in Levels 1 and 2." },
        { text: "Save your final recording. Label it 'Level 2 Complete — [date].' You are ready for Level 3: Building the Inner Ear.", why: "The labeled recording joins your growing archive of vocal development. Level 1 baseline, Level 1 completion, Level 2 diagnostic, Level 2 completion — these recordings are your vocal autobiography, documenting the journey from untrained to skilled. The transition to Level 3 shifts the focus from the mechanics of pitch production to the cognitive skill of hearing music internally — the inner ear that lets you hear a melody in your head before you sing it. The physical foundations from Levels 1 and 2 make Level 3 possible: you cannot train internal hearing until the external instrument is reliable. Your instrument is now reliable. Time to train the mind behind it." }
      ],
      feel: "This should feel like crossing a threshold — from exercises to music, from technique to expression. The backing tracks should feel inspiring, not intimidating. Your voice should feel like a more capable, more reliable version of the voice you started with. Not perfect — just better. Measurably, audibly better.",
      wrong: "Do not try to perform perfectly. This is integration, not audition. Cracks and imperfections in a musical context are normal and expected at this stage. The goal is not perfection — it is application. If you can apply 70% of what you learned in exercises to actual singing, you are right on track. The remaining 30% comes with continued practice and performance experience.",
      sarah: "Level 2 is the level where most students have their 'aha' moment — the first time they sing through the passaggio and it feels easy. It might not happen today. It might happen next week during a random practice session. But it will happen. And when it does, you will know exactly why: because you mapped your passaggio, trained it with slides and swells, modified your vowels, and practiced until the coordination became automatic. That moment of ease is not luck — it is the accumulated result of deliberate practice. Enjoy it when it arrives. You built it yourself.",
      levelUp: "Can sing a simple melody through the passaggio with lyrics, vowel modification, and breath support over a backing track. Audible improvement compared to Level 2 diagnostic recording. Ready for Level 3: Building the Inner Ear."
    }
  ]
};
